import clsx from 'clsx';
import { forwardRef, useContext, useEffect, useRef } from 'react';
import { useIntl } from 'react-intl';

import * as styles from './SegmentSelect.sty.js';
import { useMergeRefs } from '../../../../core/hooks/useMergeRefs.js';
import { isDev } from '../../../../core/utils/is-node-environment.js';
import { Select } from '../../../../forms/select/Select.js';
import type { FormControlWithOverlayRef } from '../../../../forms/shared-types.js';
import { Text } from '../../../../typography/text/Text.js';
import {
  segmentsClient,
  useSegmentsCache,
  type CachedSegment,
} from '../../contexts/SegmentsCache/SegmentsCache.js';
import {
  UISegmentsContext,
  useSegmentsUIContext,
} from '../../contexts/SegmentsUI/SegmentsUIContext.js';
import { SEGMENTSELECTOR_MESSAGES } from '../../segmentMessages.js';

type SegmentsSelectProps = {
  id: string;
  availableSegments: CachedSegment['segment'][];
  readOnly?: boolean;
  autoFocus?: boolean;
  segment?: CachedSegment | null;
  overlayWidth: string;
  triggerClassName?: string;
  isPlaceholder?: boolean;
};

function getSafeSegmentName(
  segment: CachedSegment['segment'] | null | undefined,
  fallback: string,
) {
  return segment?.name && segment.name !== '' ? segment.name : fallback;
}

/**
 * SegmentsSelect component
 * @internal
 */
export const SegmentSelect = forwardRef<
  FormControlWithOverlayRef<HTMLDivElement>,
  SegmentsSelectProps
>((props, forwardedRef) => {
  const {
    availableSegments,
    readOnly,
    triggerClassName,
    overlayWidth,
    segment: cachedSegment,
    autoFocus,
    isPlaceholder,
    id,
  } = props;
  const intl = useIntl();

  const segmentSelectRef =
    useRef<FormControlWithOverlayRef<HTMLDivElement>>(null);
  const mergedRef = useMergeRefs([forwardedRef, segmentSelectRef]);
  const variableSelectRef =
    useRef<FormControlWithOverlayRef<HTMLDivElement>>(null);

  const { updateUISegment, removeUISegment } = useSegmentsUIContext();

  const { getSegment } = useSegmentsCache();

  const { uiSegments } = useContext(UISegmentsContext);

  const refIsDefined = segmentSelectRef.current !== null;

  useEffect(() => {
    segmentsClient.hasAccessRights && segmentSelectRef.current?.validate();
    // We only want to shift the focus initially if it has autofocus (typically first select on open).
    // when the first selected one is cleared and replaced by the placeholder we want to focus the select, but not open it.
    if (uiSegments.length === 1 || autoFocus) {
      segmentSelectRef.current?.focus?.();
      return;
    }

    // If a new placeholder is added it should be opened.
    // The open also moves the focus to the hidden input which isn't available on first render.
    if (isPlaceholder && !autoFocus) {
      segmentSelectRef.current?.open();
    }

    // The hidden trigger ref (coming from the react select) is not defined after the first render and,
    // therefore, we must manually check the existence and then only once trigger the focus.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [refIsDefined]);

  return (
    <Select
      ref={mergedRef}
      className={styles.segmentsSelectCSS}
      value={id}
      id={id}
      required={!isPlaceholder}
      clearable={false}
      readOnly={readOnly || cachedSegment?.temporarilyApplied}
      onOpenChange={(isOpen) => {
        if (isOpen) {
          return;
        }

        variableSelectRef.current?.open();
      }}
      onChange={(segmentUid) => {
        if (segmentUid) {
          getSegment(segmentUid)
            .then((newSegment) => {
              updateUISegment(
                { id },
                {
                  ...newSegment.segment,
                  variables: !newSegment.segment.variables ? undefined : [],
                },
              );
            })
            .catch((error) => {
              if (isDev()) {
                // eslint-disable-next-line no-console
                console.log(
                  `SegmentSelector: fetching the segment with id ${id} failed.`,
                  error,
                );
              }
              removeUISegment(id);
            });
        }
      }}
      data-dt-name="segment-select"
    >
      <Select.Trigger
        width="full"
        className={clsx(triggerClassName, {
          [styles.segmentsSelectTriggerCSS]: cachedSegment?.segment?.variables,
        })}
        placeholder={intl.formatMessage(
          SEGMENTSELECTOR_MESSAGES.segmentsTriggerPlaceholder,
        )}
      />
      <Select.Filter />
      <Select.Content showSelectedOptionsFirst width={overlayWidth}>
        <Select.EmptyState>
          {availableSegments.length === 0
            ? intl.formatMessage(
                SEGMENTSELECTOR_MESSAGES.segmentsSelectEmptyState,
              )
            : intl.formatMessage(
                SEGMENTSELECTOR_MESSAGES.segmentsSelectEmptyStateSearch,
              )}
        </Select.EmptyState>

        {/**
         * The availableSegments removes the current selection to only show the other options.
         * This would also clear the select value and therefore this one is additionally rendered.
         */}
        {((id && !isPlaceholder) || cachedSegment?.segment) && (
          <Select.Option
            value={id}
            key={id}
            textValue={getSafeSegmentName(cachedSegment?.segment, id)}
          >
            {/** The option should wrap and not truncate, therefore, it is wrapped in a Text. */}
            <Text>{getSafeSegmentName(cachedSegment?.segment, id)}</Text>
          </Select.Option>
        )}
        {availableSegments.map((segmentOption) => (
          <Select.Option
            key={segmentOption.id}
            value={segmentOption.id}
            textValue={getSafeSegmentName(segmentOption, segmentOption.id)}
          >
            {/** The option should wrap and not truncate, therefore, it is wrapped in a Text. */}
            <Text>{getSafeSegmentName(segmentOption, segmentOption.id)}</Text>
          </Select.Option>
        ))}
      </Select.Content>
    </Select>
  );
});
